class Solution:
    def minInteger(self, num, k):
        arr = list(num)
        n = len(arr)
        remaining = k
        for i in range(n):
            if remaining <= 0:
                break
            best_j = i
            best_d = arr[i]
            limit = min(n - 1, i + remaining)
            for j in range(i + 1, limit + 1):
                if arr[j] < best_d:
                    best_d = arr[j]
                    best_j = j
            cost = best_j - i
            j = best_j
            while j > i:
                arr[j], arr[j - 1] = arr[j - 1], arr[j]
                j -= 1
            remaining -= cost
        return ''.join(arr)

