from collections import deque

class Solution:
    def minInteger(self, num, k):
        n = len(num)
        digits = [int(c) for c in num]
        pos = [deque() for _ in range(10)]
        for i, d in enumerate(digits):
            pos[d].append(i)
        bit = [0] * (n + 1)

        def update(i, delta):
            i += 1
            while i <= n:
                bit[i] += delta
                i += i & (-i)

        def query(i):
            s = 0
            while i > 0:
                s += bit[i]
                i -= i & (-i)
            return s

        for i in range(n):
            update(i, 1)
        remaining = k
        result = []
        for _ in range(n):
            for d in range(10):
                if not pos[d]:
                    continue
                original_index = pos[d][0]
                cost = query(original_index)
                if cost <= remaining:
                    pos[d].popleft()
                    update(original_index, -1)
                    remaining -= cost
                    result.append(str(d))
                    break
        return ''.join(result)

