var minInteger = function(num, k) {
    const n = num.length;
    const digits = new Array(n);
    for (let i = 0; i < n; i++) digits[i] = num.charCodeAt(i) - 48;
    const pos = Array.from({ length: 10 }, () => []);
    for (let i = 0; i < n; i++) pos[digits[i]].push(i);
    const head = new Array(10).fill(0);
    const bit = new Array(n + 1).fill(0);
    function update(i, delta) {
        i += 1;
        while (i <= n) {
            bit[i] += delta;
            i += i & (-i);
        }
    }
    function query(i) {
        let s = 0;
        while (i > 0) {
            s += bit[i];
            i -= i & (-i);
        }
        return s;
    }
    for (let i = 0; i < n; i++) update(i, 1);
    let remaining = k;
    const result = new Array(n);
    for (let idx = 0; idx < n; idx++) {
        for (let d = 0; d < 10; d++) {
            if (head[d] >= pos[d].length) continue;
            const originalIndex = pos[d][head[d]];
            const cost = query(originalIndex);
            if (cost <= remaining) {
                head[d]++;
                update(originalIndex, -1);
                remaining -= cost;
                result[idx] = String(d);
                break;
            }
        }
    }
    return result.join('');
};
